namespace McpWeatherServer;

/// <summary>
/// Typed HttpClient for the National Weather Service API.
/// Registered in DI and injected into tool classes automatically.
/// </summary>
public class WeatherApiClient(HttpClient httpClient)
{
    public async Task<Forecast?> GetForecastAsync(double latitude, double longitude, CancellationToken cancellationToken = default)
    {
        // NWS requires a point lookup first to get the forecast URL
        var point = await httpClient.GetFromJsonAsync<PointResponse>(
            $"/points/{latitude:F4},{longitude:F4}", cancellationToken);

        if (point?.Properties?.ForecastUrl is null)
            return null;

        var forecast = await httpClient.GetFromJsonAsync<ForecastResponse>(
            point.Properties.ForecastUrl, cancellationToken);

        if (forecast?.Properties is null)
            return null;

        return new Forecast
        {
            Location = $"{point.Properties.City}, {point.Properties.State}",
            Periods = forecast.Properties.Periods
                .Take(5)
                .Select(p => new ForecastPeriod
                {
                    Name = p.Name,
                    Temperature = $"{p.Temperature}°{p.TemperatureUnit}",
                    Wind = $"{p.WindSpeed} {p.WindDirection}",
                    Summary = p.ShortForecast
                })
                .ToList()
        };
    }

    public async Task<List<AlertSummary>> GetActiveAlertsAsync(string state, CancellationToken cancellationToken = default)
    {
        var response = await httpClient.GetFromJsonAsync<AlertResponse>(
            $"/alerts/active?area={state}", cancellationToken);

        return response?.Features?
            .Select(f => new AlertSummary
            {
                Event = f.Properties.Event,
                Severity = f.Properties.Severity,
                Headline = f.Properties.Headline,
                Area = f.Properties.AreaDesc
